import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"부자의 그릇","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/books/부자의-그릇.md","filePath":"outta-space/knowledge/books/부자의-그릇.md"}'),l={name:"outta-space/knowledge/books/부자의-그릇.md"};function i(n,a,_,s,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="부자의-그릇" tabindex="-1">부자의 그릇 <a class="header-anchor" href="#부자의-그릇" aria-label="Permalink to &quot;부자의 그릇&quot;">​</a></h1><h2 id="_1-핵심-내용" tabindex="-1">1. 핵심 내용 <a class="header-anchor" href="#_1-핵심-내용" aria-label="Permalink to &quot;1. 핵심 내용&quot;">​</a></h2><p>부자가 되는 방법을 자기개발서의 형태가 아닌 특이하게도 소설의 형태로 풀어낸 책이다.</p><h2 id="_2-문체와-가독성" tabindex="-1">2. 문체와 가독성 <a class="header-anchor" href="#_2-문체와-가독성" aria-label="Permalink to &quot;2. 문체와 가독성&quot;">​</a></h2><p>문장이 가볍고 진지하지 않아 쉽게 읽힌다. 술술 읽히는 쉬운 책.</p><h2 id="_3-저자의-관점과-설득력" tabindex="-1">3. 저자의 관점과 설득력 <a class="header-anchor" href="#_3-저자의-관점과-설득력" aria-label="Permalink to &quot;3. 저자의 관점과 설득력&quot;">​</a></h2><p>이 책이 가장 말하고 싶은 것은 결국 많은 돈을 만질 수 있는 그릇이 되어야 부자가 될 수 있다는 것이다. 뭐 제목에서부터 알 수 있겠지만, 사람의 인격이나 능력을 키워야만 부자가 된다는 것을 책 시작부터 끝까지 강조한다.</p><h2 id="_4-인상-깊은-문장-장면" tabindex="-1">4. 인상 깊은 문장 / 장면 <a class="header-anchor" href="#_4-인상-깊은-문장-장면" aria-label="Permalink to &quot;4. 인상 깊은 문장 / 장면&quot;">​</a></h2><ul><li>인간이 돈 때문에 저지르는 실수 중 대부분은 잘못된 타이밍과 선택으로 인해 일어난다. 사람마다 다룰 수 있는 돈의 크기가 다르다. 돈을 다루는 능력은 많이 다뤄봐야만 향상된다. 돈은 그 사람을 비추는 거울이다. 돈은 신용이 모습을 바꾼 것이다.</li></ul><h2 id="_5-나에게-남은-생각" tabindex="-1">5. 나에게 남은 생각 <a class="header-anchor" href="#_5-나에게-남은-생각" aria-label="Permalink to &quot;5. 나에게 남은 생각&quot;">​</a></h2><p>뭐 별 거 없다. 평소에 생각하던 것을 길게 책으로 읽으니 지루했다.</p>',11)])])}const u=e(l,[["render",i]]);export{p as __pageData,u as default};
